SELECT manufacturers.manufacturer_name, pumps.pump_type 
FROM manufacturers 
JOIN pumps ON manufacturers.manufacturer_id = pumps.manufacturer_id;

SELECT COUNT(DISTINCT supplier_id)
FROM pump_suppliers
WHERE lead_time > 10;

SELECT model_name, year_introduced, weight
FROM pump_models
ORDER BY year_introduced DESC;

SELECT model_id, AVG(sale_price) AS average_sale_price
FROM pump_sales
GROUP BY model_id;

SELECT AVG(efficiency) AS average_efficiency
FROM (
  SELECT *
  FROM pumps
  WHERE max_lift_height = (SELECT MAX(max_lift_height) FROM pumps)
) AS greatest_lift_pumps;

SELECT m.manufacturer_id, m.manufacturer_name, m.location, m.contact_email, m.phone_number, m.website, m.established_year, m.number_of_employees, m.specialization
FROM manufacturers m
INNER JOIN pumps p ON m.manufacturer_id = p.manufacturer_id
WHERE p.pump_type = 'Continuous bucket pump' AND p.production_cost > (
    SELECT AVG(production_cost) FROM pumps
);

SELECT pump_type, max_lift_height, output
FROM pumps
ORDER BY max_lift_height DESC;

SELECT pump_type, AVG(efficiency) AS average_efficiency
FROM pumps
GROUP BY pump_type;

SELECT m.pump_id, m.maintenance_date, m.next_maintenance_date, p.test_date, p.flow_rate, p.pressure, p.efficiency_rating, p.test_environment, p.test_duration, p.test_method, p.test_conducted_by
FROM pump_maintenance m
JOIN pump_performance p ON m.pump_id = p.model_id;

SELECT u.username 
FROM user_accounts u
JOIN pump_maintenance pm ON u.user_id = pm.maintenance_technician_id;
